import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"难经","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/01-先秦两汉/05-难经.md","filePath":"tcm-data/01-先秦两汉/05-难经.md","lastUpdated":1781084559000}'),r={name:"tcm-data/01-先秦两汉/05-难经.md"};function i(n,t,s,d,h,g){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="难经" tabindex="-1">难经 <a class="header-anchor" href="#难经" aria-label="Permalink to &quot;难经&quot;">​</a></h1><blockquote><p>全名《黄帝八十一难经》，托名秦越人（扁鹊） 以问答体阐释《内经》疑难的专著</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>成书</strong>：西汉（约公元前2-1世纪），晚于《内经》</li><li><strong>作者</strong>：旧题扁鹊（秦越人），实非一人之作</li><li><strong>体例</strong>：八十一难（问答），每难解答一个中医理论问题</li><li><strong>学术地位</strong>：中医四大经典之一（虽有争议，但为历代医家必读）</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-独取寸口诊脉法-第一难" tabindex="-1">1. 独取寸口诊脉法（第一难） <a class="header-anchor" href="#_1-独取寸口诊脉法-第一难" aria-label="Permalink to &quot;1. 独取寸口诊脉法（第一难）&quot;">​</a></h3><blockquote><p><strong>「十二经皆有动脉，独取寸口，以决五脏六腑死生吉凶之法。」</strong></p></blockquote><ul><li>将寸口脉分为 <strong>寸、关、尺</strong> 三部</li><li>每部又分 <strong>浮、中、沉</strong> 三候（三九二十七）</li><li>左：寸（心）、关（肝）、尺（肾）</li><li>右：寸（肺）、关（脾）、尺（命门）</li><li><strong>&quot;独取寸口&quot;成为中医诊脉的标准方法，沿用至今</strong></li></ul><h3 id="_2-命门学说-第三十六难" tabindex="-1">2. 命门学说（第三十六难） <a class="header-anchor" href="#_2-命门学说-第三十六难" aria-label="Permalink to &quot;2. 命门学说（第三十六难）&quot;">​</a></h3><blockquote><p><strong>「肾两者，非皆肾也。其左者为肾，右者为命门。命门者，诸神精之所舍，原气之所系也，男子以藏精，女子以系胞。」</strong></p></blockquote><ul><li>首次提出<strong>命门</strong>概念（右肾为命门）</li><li>命门=生命之门=元气的根本</li><li><strong>对后世影响极大</strong>：明代张介宾、清代黄元御等都发展了命门学说</li></ul><h3 id="_3-七冲门-第四十四难" tabindex="-1">3. 七冲门（第四十四难） <a class="header-anchor" href="#_3-七冲门-第四十四难" aria-label="Permalink to &quot;3. 七冲门（第四十四难）&quot;">​</a></h3><blockquote><p><strong>「唇为飞门，齿为户门，会厌为吸门，胃为贲门，太仓下口为幽门，大肠小肠会为阑门，下极为魄门。」</strong></p></blockquote><h3 id="_4-脏腑重量形态" tabindex="-1">4. 脏腑重量形态 <a class="header-anchor" href="#_4-脏腑重量形态" aria-label="Permalink to &quot;4. 脏腑重量形态&quot;">​</a></h3><p>《难经》详细记录了五脏六腑的<strong>重量、大小、容量</strong>（如心重十二两、肝重四斤四两等），是中医最早的解剖学记载。</p><h3 id="_5-泻南补北-七十五难" tabindex="-1">5. 泻南补北（七十五难） <a class="header-anchor" href="#_5-泻南补北-七十五难" aria-label="Permalink to &quot;5. 泻南补北（七十五难）&quot;">​</a></h3><blockquote><p><strong>「东方实，西方虚，泻南方，补北方。」</strong></p></blockquote><ul><li>东方 = 肝（实）→ 南方 = 心 → 北方 = 肾</li><li>泻心火 → 补肾水 → 滋养肝木</li><li>这是一种<strong>间接治疗</strong>思路</li></ul><h3 id="_6-五邪理论" tabindex="-1">6. 五邪理论 <a class="header-anchor" href="#_6-五邪理论" aria-label="Permalink to &quot;6. 五邪理论&quot;">​</a></h3><blockquote><p><strong>「中风、伤暑、饮食劳倦、伤寒、中湿，此之谓五邪。」</strong></p></blockquote><hr><h2 id="三、历代注家" tabindex="-1">三、历代注家 <a class="header-anchor" href="#三、历代注家" aria-label="Permalink to &quot;三、历代注家&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">注家</th><th style="text-align:left;">著作</th></tr></thead><tbody><tr><td style="text-align:left;">三国吴</td><td style="text-align:left;">吕广</td><td style="text-align:left;">《难经注解》（最早注本，已佚）</td></tr><tr><td style="text-align:left;">唐</td><td style="text-align:left;">杨玄操</td><td style="text-align:left;">《难经注解》</td></tr><tr><td style="text-align:left;">元</td><td style="text-align:left;">滑寿</td><td style="text-align:left;">《难经本义》（最流行的注本之一）</td></tr><tr><td style="text-align:left;">明</td><td style="text-align:left;">王九思</td><td style="text-align:left;">《难经集注》（集吕、杨、滑等注）</td></tr><tr><td style="text-align:left;">清</td><td style="text-align:left;">徐灵胎</td><td style="text-align:left;">《难经经释》</td></tr><tr><td style="text-align:left;">近代</td><td style="text-align:left;">吴考槃</td><td style="text-align:left;">《难经汇注》</td></tr></tbody></table><hr><h2 id="四、对后世的影响" tabindex="-1">四、对后世的影响 <a class="header-anchor" href="#四、对后世的影响" aria-label="Permalink to &quot;四、对后世的影响&quot;">​</a></h2><h3 id="临床价值" tabindex="-1">临床价值 <a class="header-anchor" href="#临床价值" aria-label="Permalink to &quot;临床价值&quot;">​</a></h3><ol><li><strong>独取寸口</strong>——诊脉法的标准化</li><li><strong>命门学说</strong>——为温补学派提供理论来源</li><li><strong>奇经八脉理论</strong>——补充《内经》经络学说</li><li><strong>五输穴理论</strong>——针灸取穴的核心依据</li></ol><h3 id="黄元御与《难经》" tabindex="-1">黄元御与《难经》 <a class="header-anchor" href="#黄元御与《难经》" aria-label="Permalink to &quot;黄元御与《难经》&quot;">​</a></h3><p>黄元御所称&quot;四圣&quot;——黄帝、岐伯、越人（扁鹊）、仲景——越人即指《难经》作者。他的**&quot;一气周流&quot;模型**与《难经》的命门学说、元气理论有深刻关联。</p><hr><p><em>本条目为精简框架版。可在后续扩展中详细整理八十一问的逐问解析。</em></p>',33)])])}const q=e(r,[["render",i]]);export{c as __pageData,q as default};
